## Code Example
```typescript
// CDK Stack: us-east-1 Region
import { Stack, StackProps } from 'aws-cdk-lib';
import { Construct } from 'constructs';
import { KinesisStream } from 'aws-cdk-lib/aws-kinesis';
import { LambdaFunction } from 'aws-cdk-lib/aws-lambda-event-sources';
import { NodejsFunction } from 'aws-cdk-lib/aws-lambda-nodejs';
import { Table, BillingMode } from 'aws-cdk-lib/aws-dynamodb';

export class AnalyticsStackEast extends Stack {
  constructor(scope: Construct, id: string, props?: StackProps) {
    super(scope, id, props);

    const stream = new KinesisStream(this, 'AnalyticsStream', {
      streamName: 'analytics-stream-us-east-1',
      shardCount: 4,
      retentionPeriod: Duration.hours(24)
    });

    const processorFn = new NodejsFunction(this, 'ProcessorFunction', {
      entry: 'src/processor.ts',
      handler: 'handler',
      environment: { REGION: 'us-east-1' }
    });

    processorFn.addEventSource(new KinesisStreamSource(stream));

    const table = new Table(this, 'AnalyticsTable', {
      tableName: 'analytics-us-east-1',
      billingMode: BillingMode.PAY_PER_REQUEST,
      partitionKey: { name: 'pk', type: AttributeType.STRING },
      sortKey: { name: 'sk', type: AttributeType.STRING }
    });

    table.grantWriteData(processorFn);
  }
}
```

