import * as cdk from 'aws-cdk-lib';
import * as globals from 'aws-cdk-lib/global-ss'; // pseudocode

export class BiddingApiStack extends cdk.Stack {
  constructor(scope: cdk.Construct, id: string, props?: cdk.StackProps) {
