export class StreamingAnalyticsStack extends cdk.Stack {
  constructor(scope: cdk.App, id: string, props: StreamingAnalyticsStackProps) {
    super(scope, id, props);

    const encryptionKey = new kms.Key(this, 'DataEncryptionKey', {
      enableKeyRotation: true,
      removalPolicy: cdk.RemovalPolicy.RETAIN,
    });

    const dataBucket = new s3.Bucket(this, 'DataBucket', {
      encryption: s3.BucketEncryption.KMS,
      encryptionKey,
      versioning: true,
    });

    const stream = new kinesis.Stream(this, 'AnalyticsStream', {
      encryption: kinesis.StreamEncryption.KMS,
      encryptionKey,
    });

    const lambdaRole = new iam.Role(this, 'LambdaRole', {
      assumedBy: new iam.ServicePrincipal('lambda.amazonaws.com'),
      managedPolicies: [
        iam.ManagedPolicy.fromAwsManagedPolicyName('service-role/AWSLambdaBasicExecutionRole'),
      ],
    });

    encryptionKey.grantEncryptDecrypt(lambdaRole);
    dataBucket.grantReadWrite(lambdaRole);
  }
}

class PipelineStack extends cdk.Stack {
  constructor(scope: cdk.App, id: string, props: cdk.StackProps) {
    super(scope, id, props);

    const pipeline = new CodePipeline(this, 'MultiRegionPipeline', {
      pipelineName: 'streaming-analytics-pipeline',
      synth: new ShellStep('Synth', {
        input: CodePipelineSource.gitHub('org/repo', 'main'),
        commands: ['npm install', 'npm run build', 'npx cdk synth'],
      }),
    });

    const stages: ('dev' | 'staging' | 'production')[] = ['dev', 'staging', 'production'];
    const regions = {
      dev: 'us-east-1',
      staging: 'us-east-1',
      production: 'us-east-1',
    };

    stages.forEach((stage, index) => {
      const stagePipeline = pipeline.addStage(new AppStage(this, stage, {
        env: { account: process.env[`${stage.toUpperCase()}_ACCOUNT`]!, region: regions[stage] },
      }));

      stagePipeline.addPost(new CloudFormationCreateUpdateStackAction({
        actionName: 'Deploy',
        stackName: `streaming-analytics-${stage}`,
        templatePath: Artifact.artifactPath(`StackOutput.template.json`),
        adminPermissions: true,
      }));

      if (stage === 'production') {
        stagePipeline.addPost(new ManualApprovalAction({
          actionName: 'ProductionApproval',
        }));
      }
    });
  }
}
