// CDK pre-deploy validation gate
import { Stack } from 'aws-cdk-lib';
import { Secret } from 'aws-cdk-lib/aws-secretsmanager';

interface SecretValidationResult {
  valid: boolean;
  violations: string[];
}

async function validateSecretsRotation(stack: Stack): Promise<SecretValidationResult> {
  const violations: string[] = [];

  const secrets = stack.node.findAll().filter(
    node => node instanceof Secret
  );

  for (const secret of secrets) {
    const describeResult = await secret.secret.describe();

    if (!describeResult.rotationEnabled) {
      violations.push(`Secret ${secret.secretName} has rotation disabled`);
    }

    const lastRotated = new Date(describeResult.lastRotatedDate || 0);
    const daysSinceRotation = (Date.now() - lastRotated.getTime()) / (1000 * 60 * 60 * 24);

    if (daysSinceRotation > 30) {
      violations.push(`Secret ${secret.secretName} last rotated ${Math.floor(daysSinceRotation)} days ago`);
    }
  }

  return { valid: violations.length === 0, violations };
}
