## OPA Gatekeeper Constraint Template
```yaml
apiVersion: templates.gatekeeper.sh/v1
kind: ConstraintTemplate
metadata:
  name: secretsmustrotateregularly
spec:
  crd:
    spec:
      names:
        kind: SecretsMustRotateRegularly
      validation:
        openAPIV3Schema:
          type: object
          properties:
            maxDaysSinceRotation:
              type: integer
              minimum: 1
  targets:
    - target: admission.k8s.gatekeeper.sh
      rego: |
        package secretsmustrotateregularly

        violation["secret %s has rotation disabled or last rotation exceeded %d days"] {
          input.review.object.kind == "Secret"
          secret := input.review.object
          not secret.data.{"aws:RotationEnabled": "true"}
          maxDays := input.parameters.maxDaysSinceRotation
          daysSinceRotation := time.diff(time.now(), secret.metadata.annotations.{"aws:LastRotatedDate"}) / (24 * 60 * 60)
          daysSinceRotation > maxDays
        }
```

